"""token_budget.py — accurate token budgeting for OpenAI chat APIs."""
from __future__ import annotations
import tiktoken
from dataclasses import dataclass, field
from typing import List, Dict, Any

@dataclass
class TokenBudget:
    model: str
    max_context: int
    reserved_output: int = 4096
    _enc: Any = field(init=False, repr=False)

    def __post_init__(self):
        # tiktoken selects encoding by model name
        try:
            self._enc = tiktoken.encoding_for_model(self.model)
        except KeyError:
            # fall back to cl100k_base for unknown model names
            self._enc = tiktoken.get_encoding("cl100k_base")

    def count_text(self, text: str) -> int:
        return len(self._enc.encode(text))

    def count_messages(self, messages: List[Dict]) -> int:
        """Count tokens in an OpenAI-format messages list including per-message overhead."""
        total = 2  # priming tokens for assistant reply
        for msg in messages:
            total += 4  # per-message overhead (<|im_start|>, role, newline, <|im_sep|>)
            for key, value in msg.items():
                total += self.count_text(str(value))
                if key == "name":
                    total -= 1  # 'name' field saves one token on 'role'
        return total

    def available_input(self, messages: List[Dict]) -> int:
        """How many more tokens can be added to messages before hitting the limit."""
        used = self.count_messages(messages)
        return self.max_context - self.reserved_output - used

    def fits(self, messages: List[Dict]) -> bool:
        return self.available_input(messages) >= 0

    def prune_history(
        self,
        messages: List[Dict],
        keep_system: bool = True,
    ) -> List[Dict]:
        """Drop oldest non-system messages until the budget is satisfied."""
        result = list(messages)
        while not self.fits(result) and len(result) > (1 if keep_system else 0):
            # Remove the second message (index 1) to preserve the system prompt
            drop_idx = 1 if keep_system and result[0]["role"] == "system" else 0
            result.pop(drop_idx)
        return result


# Example usage
if __name__ == "__main__":
    budget = TokenBudget(model="gpt-4o", max_context=128_000, reserved_output=4_096)

    messages = [
        {"role": "system", "content": "You are a helpful code review agent."},
        {"role": "user",   "content": "Review the following code: " + "x = 1\n" * 500},
        {"role": "assistant", "content": "The code looks fine."},
        {"role": "user",   "content": "Now explain the algorithm."},
    ]

    print(f"Messages token count : {budget.count_messages(messages):,}")
    print(f"Available for output : {budget.available_input(messages):,}")
    print(f"Fits in context      : {budget.fits(messages)}")

"""sliding_window.py — drop oldest turns to stay within budget."""
import tiktoken
from typing import List, Dict

class SlidingWindowHistory:
    """Maintains conversation history within a token budget using a sliding window."""

    def __init__(self, max_tokens: int, reserved_output: int = 4096, model: str = "gpt-4o"):
        self.max_tokens = max_tokens
        self.reserved_output = reserved_output
        self._enc = tiktoken.encoding_for_model(model)
        self._history: List[Dict] = []

    def _count(self, messages: List[Dict]) -> int:
        total = 2
        for msg in messages:
            total += 4 + len(self._enc.encode(msg.get("content", "")))
        return total

    @property
    def budget(self) -> int:
        return self.max_tokens - self.reserved_output

    def add(self, role: str, content: str) -> None:
        self._history.append({"role": role, "content": content})
        # Evict oldest non-system turns until we fit
        while self._count(self._history) > self.budget and len(self._history) > 1:
            self._history.pop(0)

    def messages(self) -> List[Dict]:
        return list(self._history)

    def usage_report(self) -> str:
        used = self._count(self._history)
        pct = used / self.budget * 100
        return f"{used:,}/{self.budget:,} tokens ({pct:.1f}% of input budget)"


if __name__ == "__main__":
    window = SlidingWindowHistory(max_tokens=4096, reserved_output=512, model="gpt-4o")
    for i in range(20):
        window.add("user", f"This is turn {i}. " + "Some longer text. " * 10)
        window.add("assistant", f"Acknowledged turn {i}. " + "Reply text. " * 8)
        print(f"Turn {i:2d}: {window.usage_report()}  messages={len(window.messages())}")
